// STEP 3 — Entity Association (the critical parsing step)
// Input: rows from the Spreadsheet File node (header row 11 → keys: Unit, Name,
// Amount Receivable, Last Payment, Payment Amount, 0-30, 30+, Rent, Primary Tenant Email).
// Output: ONE item per tenant data row, each with _entity_name and _property_address
// attached. Entity-header rows and subtotal/grand-total rows are consumed/skipped.
try {
  let currentEntity = '';
  let currentAddress = '';
  const tenantRows = [];

  for (const item of items) {
    const j = item.json || {};
    const unit = (j['Unit'] || '').toString().trim();
    const name = (j['Name'] || '').toString().trim();
    const amountReceivable = j['Amount Receivable'];

    // Skip fully empty rows
    if (!unit && !name && (amountReceivable === undefined || amountReceivable === null || amountReceivable === '')) {
      continue;
    }

    // Entity header row: Column A populated, Column B (Name) empty, contains " - "
    if (unit && !name && unit.includes(' - ')) {
      const parts = unit.split(' - ');
      currentEntity = parts[0].trim();
      currentAddress = parts.slice(1).join(' - ').trim();
      continue;
    }

    // Grand total row: Unit === "Total"
    if (unit === 'Total') {
      continue;
    }

    // Subtotal rows: no Name value (numeric-only rows after each entity group)
    if (!name || name === 'Total') {
      continue;
    }

    // Tenant data row — attach the current entity context
    j._entity_name = currentEntity;
    j._property_address = currentAddress;
    tenantRows.push({ json: j });
  }

  return tenantRows;
} catch (err) {
  // Surface a clear error so the Error Trigger path can report it
  throw new Error('Step 3 entity association failed: ' + (err && err.message ? err.message : String(err)));
}
